#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int fav[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &fav[i]);
        }
        int K;
        scanf("%d", &K);
        int marks[K];
        for (int i = 0; i < K; i++) {
            scanf("%d", &marks[i]);
        }
        qsort(fav, N, sizeof(int), compare);
        int total_marks = 0;
        int prev_marks = 0;
        for (int i = 0; i < N; i++) {
            int min_marks = prev_marks * 2 + 1;
            int marks_given = 0;
            for (int j = 0; j < K; j++) {
                if (marks[j] >= min_marks) {
                    marks_given = marks[j];
                    break;
                }
            }
            total_marks += marks_given;
            prev_marks = marks_given;
        }
        printf("%.6f\n", (double)total_marks / N);
    }
    return 0;
}

