import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] fav = new int[N];
            for (int i = 0; i < N; i++) {
                fav[i] = sc.nextInt();
            }
            int K = sc.nextInt();
            int[] marks = new int[K];
            for (int i = 0; i < K; i++) {
                marks[i] = sc.nextInt();
            }
            Arrays.sort(fav);
            int total_marks = 0;
            int prev_marks = 0;
            for (int i = 0; i < N; i++) {
                int min_marks = prev_marks * 2 + 1;
                int marks_given = 0;
                for (int j = 0; j < K; j++) {
                    if (marks[j] >= min_marks) {
                        marks_given = marks[j];
                        break;
                    }
                }
                total_marks += marks_given;
                prev_marks = marks_given;
            }
            System.out.printf("%.6f\n", (double)total_marks / N);
        }
    }
}

