function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let N = nextInt();
    let fav = nextIntArray();
    let K = nextInt();
    let marks = nextIntArray();
    fav.sort((a, b) => a - b);
    let total_marks = 0;
    let prev_marks = 0;
    for (let i = 0; i < N; i++) {
        let min_marks = prev_marks * 2 + 1;
